INSERT INTO menu_grp (
menu_grp_id, store_id, menu_grp_name, use_yn, menu_grp_position, created_user
) VALUES (
#{menuGrpId}, #{storeId}, #{menuGrpName}, #{useYn}, #{menuGrpPosition}, #{createdUser}
)
ON DUPLICATE KEY UPDATE
menu_grp_name = VALUES(menu_grp_name),
use_yn = VALUES(use_yn),
menu_grp_position = VALUES(menu_grp_position),
updated_at = CURRENT_TIMESTAMP,
updated_user = #{updatedUser}
